result:
* {
  box-sizing: border-box;
  user-select: none;
}
a {
  cursor: pointer;
}
.main {
  background: #565656;
  box-sizing: border-box;
  margin: 0;
  padding: 0;
  position: absolute;
  top: 0;
  left: 0;
  bottom: 0;
  right: 0;
  color: #eee;
  height: 100%;
  .user-status {
    position: absolute;
    top: 0.1rem;
    left: 0.1rem;
    border: 2px solid #ccc;
    height: 4rem;
    width: 4rem;
    padding: 0.1rem;
    display: flex;
    flex-direction: column;
    .hp {
      cursor: pointer;
      height: 0.7rem;
      width: 100%;
      display: flex;
      border: 2px solid #ccc;
      align-items: center;
      padding-left: 0.2rem;
      margin-bottom: 0.1rem;
      img {
        width: 0.5rem;
        height: 0.5rem;
      }
      .value {
        font-size: 0.26rem;
        font-weight: bold;
        text-align: center;
        flex: 1;
      }
    }
    .lv {
      cursor: pointer;
      height: 0.7rem;
      width: 100%;
      display: flex;
      border: 2px solid #ccc;
      align-items: center;
      padding-left: 0.2rem;
      margin-bottom: 0.1rem;
      img {
        width: 0.5rem;
        height: 0.5rem;
      }
      .value {
        display: flex;
        justify-content: space-around;
        font-size: 0.26rem;
        font-weight: bold;
        text-align: center;
        flex: 1;
        align-items: center;
      }
    }
    .other {
      img {
        width: 0.35rem !important;
        height: 0.35rem !important;
      }
      display: flex;
      flex: 1;
      padding: 0.1rem;
      border: 2px solid #ccc;
      flex-wrap: wrap;
      & > div,
      .item {
        cursor: pointer;
        width: 33.3%;
        height: 50%;
        display: flex;
        align-items: center;
        justify-content: flex-start;
        padding-top: 0.05rem;
        flex-direction: column;
        .value {
          margin-top: 0.06rem;
          font-size: 0.23rem;
          font-weight: normal;
          flex: 1;
          display: flex;
          align-items: center;
          flex-direction: column;
        }
      }
      .item {
        width: 100%;
      }
    }
  }
  .user-item {
    position: absolute;
    top: 0.1rem;
    left: 4.2rem;
    border: 2px solid #ccc;
    height: 4rem;
    width: 4rem;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: space-around;
    padding: 0.2rem 0;
    padding-top: 0.1rem;
    cursor: pointer;
    & > div {
      background: rgba(0, 0, 0, 0.7);
      width: calc(100% - 0.4rem);
      margin: 0 20rem;
    }
    .uii {
      display: flex;
      width: calc(100% - 0.4rem);
    }
    .gold {
      cursor: pointer;
      height: 0.7rem;
      margin: 0.1rem;
      margin-top: 0.08rem;
      width: calc(100%);
      display: flex;
      align-items: center;
      padding-left: 0.1rem;
      font-size: 0.22rem;
      span {
        font-size: 0.2rem;
        font-weight: bold;
        text-align: right;
        flex: 1;
        padding: 0.1rem 0.08rem;
        display: flex;
        align-items: flex-end;
        justify-content: flex-end;
      }
    }
    .title {
      display: flex;
      padding: 0.05rem;
      width: 100%;
      .icon {
        width: 0.56rem;
        height: 0.56rem;
        background-color: #000;
        display: flex;
        align-items: center;
        justify-content: center;
        border-radius: 0.04rem;
      }
      .name {
        font-size: 0.2rem;
        height: 0.46rem;
        margin-left: 0.2rem;
        line-height: 0.46rem;
      }
    }
  }
  .sys-info {
    position: absolute;
    border: 2px solid #ccc;
    height: calc(100% - 4.4rem);
    width: 8.1rem;
    bottom: 0.1rem;
    left: 0.1rem;

    transition: 0.2s;
    padding: 0.2rem;
    .clear {
      position: absolute;
      top: 0.2rem;
      right: 0.2rem;
      cursor: pointer;
      &:hover {
        text-decoration: underline;
      }
    }
    #sysInfo {
      overflow-y: auto;
      transition: 0.2s;
      width: 100%;
      height: 100%;
      display: flex;
      flex-direction: column;
      align-items: flex-start;
      justify-content: flex-start;
    }
    .info {
      margin: 0.03rem 0;
    }
    a {
      cursor: pointer;
      text-decoration: underline;
      margin-left: 0.05rem;
    }
    .warning > span {
      color: #f90202;
    }
    .battle > span {
      color: #de8618;
    }
    .win > span {
      color: #24c4de;
    }
    .trophy > span {
      color: #2fe20f;
    }
  }
  .map {
    position: absolute;
    right: 0.1rem;
    left: 8.3rem;
    top: 0.1rem;
    bottom: 0.1rem;
    border: 2px solid #ccc;
    background-image: url(../assets/img/map.jpg);
    background-repeat: no-repeat;
    background-size: 100% 100%;
    .plan {
      position: absolute;
      top: 0.1rem;
      width: calc(100% - 0.3rem);
      left: 0.15rem;
      height: 1rem;
      background: rgba(54, 121, 176, 0.68);
      text-align: center;
      font-size: 0.4rem;
      line-height: 1rem;
    }
    .eventEnd {
      position: absolute;
      top: 1.1rem;
      right: 0rem;
      height: 0.4rem;
      font-size: 0.16rem;
      line-height: initial;
    }
    .event-icon {
      position: absolute;
      cursor: pointer;
      width: 0.55rem;
      height: 0.75rem;
      border: 1px solid #111;
      background: rgba(0, 0, 0, 0.5);
      border-radius: 4px;
      box-shadow: 0 0 4px 4px rgba(100, 255, 36, 0.5);
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      // transform: translate(-50%, -50%);
      // background-image: url(../assets/icons/icon_81.png);
      // background-repeat: no-repeat;
      // background-position: top center;
      // background-color: rgba(245, 54, 54, 0.7);
      // background-size: 30px 29px;
      .icon-image {
        width: 0.45rem;
        height: 0.45rem;
        border-radius: 50%;
        background-image: url(../assets/icons/menu/d1.png);
        background-color: rgba(100, 255, 36, 0.6);
        background-repeat: no-repeat;
        background-position: center center;
        background-size: 30px 29px;
      }
      span {
        // position: absolute;
        // top: 100%;
        // left: 50%;
        // transform: translateX(-50%);
        text-shadow: 1px 1px 3px rgb(0, 0, 0);
        white-space: nowrap;
        width: 100%;
        text-align: center;
        border-top: 1px solid rgba(100, 255, 36, 0.6);
        margin-top: 0.03rem;
        font-size: 0.14rem;
      }
    }
    .low-level {
      // background-image: url(../assets/icons/menu/d1.png);
      // background-color: rgba(100, 255, 36, 0.7);
    }
    .h-level {
      box-shadow: 0 0 4px 4px rgba(245, 241, 0, 0.5);
      .icon-image {
        background-image: url(../assets/icons/menu/d2.png);
        background-color: rgba(245, 241, 0, 0.6);
      }
      span {
        border-top: 1px solid rgba(245, 241, 0, 0.6);
      }
      // background-image: url(../assets/icons/menu/d2.png);
      // background-color: rgba(245, 241, 0, 0.7);
    }
    .boss {
      box-shadow: 0 0 4px 4px rgba(245, 54, 54, 0.5);
      .icon-image {
        background-image: url(../assets/icons/menu/d3.png);
        background-color: rgba(245, 54, 54, 0.6);
      }
      span {
        border-top: 1px solid rgba(245, 54, 54, 0.6);
      }
      // background-image: url(../assets/icons/menu/d3.png);
    }
    .endless {
      box-shadow: 0 0 4px 4px rgba(245, 69, 0, 0.5);
      .icon-image {
        background-image: url(../assets/icons/endless.png);
        background-color: rgba(245, 69, 0, 0.6);
      }
      span {
        border-top: 1px solid rgba(245, 69, 0, 0.6);
      }
    }
  }
}
.dialog {
  position: absolute;
  display: none;
  z-index: 10;
  & > div {
    margin: 0.1rem;
  }
  display: flex;
  justify-content: space-between;
}
.weaponShow {
  top: 0.67rem;
  left: 7.98rem;
  display: flex;
}
.armorShow {
  top: 1.77rem;
  left: 7.98rem;
  display: flex;
}
.ringShow {
  top: 2.77rem;
  left: 7.98rem;
  display: flex;
}
.menu {
  position: absolute;
  bottom: 0.15rem;
  background: rgba($color: #000000, $alpha: 0.4);
  left: 8.33rem;
  padding: 0.1rem;
  border-top-right-radius: 0.1rem;
  display: flex;
  & > div {
    display: flex;
    align-items: center;
    flex-direction: column;
    cursor: pointer;
    margin: 0 0.2rem;
    justify-content: space-between;
    span {
      color: #fff;
      font-size: 0.3rem;
      line-height: 0.3rem;
      padding: 0.1rem 0;
      font-weight: bold;
      text-shadow: 1px 1px 3px rgb(0, 0, 0);
    }
  }
}
.dialog-backpackPanel {
  position: absolute;
  z-index: 9;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  border: 2px solid #fff;
  border-radius: 6px;
  box-shadow: 0 0 5px 5px rgba(0, 0, 0, 0.7);
  background: rgba(0, 0, 0, 0.7);
  .title {
    display: flex;
    position: relative;
    align-items: center;
    justify-content: center;
    font-size: 20px;
    padding: 0.1rem;
    height: 0.6rem;
    border-bottom: 1px solid #ccc;
    .close {
      cursor: pointer;
      position: absolute;
      top: 0.13rem;
      right: 0.15rem;
      display: block;
      width: 0.3rem;
      height: 0.3rem;
      background-image: url(../assets/icons/close.png);
      background-size: cover;
    }
  }
  .body {
    padding: 0.1rem;
    display: flex;
    flex-direction: column;
    .prompt-message {
      font-size: 0.12rem;
      margin: 0.04rem 0;
    }
  }
  .savedata-textarea {
    width: 300px;
    height: 180px;
    user-select: text;
    padding: 2px;
    background: rgba($color: #ffffff, $alpha: 0.8);
  }
  .footer {
    border-top: 1px solid #ccc;
    padding: 0.06rem;
    display: flex;
    align-items: center;
    justify-content: center;
  }
}
.item-close {
  display: none;
  position: absolute;
  top: -0.52rem;
  right: 50%;
  transform: translateX(68%);
  background: #000;
  padding: 0.04rem 0.1rem;
  border-radius: 0.06rem;
  border: 1px solid #fff;
}
.close {
  cursor: pointer;
  display: block;
  width: 0.25rem;
  height: 0.25rem;
  background-image: url(../assets/icons/close.png);
  background-size: cover;
}
.gm-panel {
  width: 5rem;
  height: 3rem;
  .content {
    input {
      padding: 0.05rem 0.1rem;
      width: 1.4rem;
    }
    flex-direction: column;
    display: flex;
    justify-content: center;
    padding: 0.1rem;
    align-items: center;
    justify-content: center;
  }
}
.dungeons-Info {
  z-index: 2;
  position: absolute;
  top: 50%;
  left: 50%;
  transform: translate(-50%, -50%);
  width: 3.5rem;
  background: rgba(0, 0, 0, 0.7);
  border-radius: 4px;
  border: 2px solid #ccc;
  height: 3.5rem;
  padding: 0.1rem;
  .info {
    padding: 0.1rem 0.2rem;
    font-size: 0.12rem;
    color: #999;
  }
  .dungeons-close {
    cursor: pointer;
    position: absolute;
    top: 0.1rem;
    right: 0.1rem;
    display: block;
    width: 0.23rem;
    height: 0.23rem;
    background-image: url(../assets/icons/close.png);
    background-size: cover;
  }
  .dungeons-re {
    cursor: pointer;
    position: absolute;
    top: 0.1rem;
    right: 0.5rem;
    display: block;
    width: 0.23rem;
    height: 0.23rem;
    background-image: url(../assets/icons/re.png);
    background-size: cover;
  }
  .dungeons-title {
    margin-top: 0.1rem;
    font-size: 0.22rem;
    margin-bottom: 0.2rem;
  }
  .handle {
    display: flex;
    align-items: center;
    justify-content: space-between;
    white-space: nowrap;
    font-size: 0.14rem;
    margin-top: 0.1rem;
    & > div {
      display: flex;
      align-items: center;
    }
    p {
      display: flex;
      align-items: center;
    }
    input {
      width: 0.2rem;
      height: 0.2rem;
      min-height: 15px;
      min-width: 15px;
      margin-right: 0.05rem;
    }
  }
  .handle-column {
    display: flex;
    flex-direction: column;
    p {
      display: flex;
      align-items: center;
    }
  }
  .jjj {
    font-size: 0.16rem;
    width: 100%;
    justify-content: space-between;
    display: flex;
    padding: 0.15rem 0.25rem;
    align-items: center;
    .dungeons-dps {
      color: #f90202;
      text-shadow: 0px 0px 2px rgba(245, 54, 54, 0.7);
    }
    .dungeons-difficulty {
      text-align: right;
    }
  }
  .desc {
    width: 100%;
    height: 1.5rem;
    font-size: 0.14rem;
    border-top: 1px solid #ccc;
    padding: 0.1rem;
    color: #999;
  }
  .dungeons-btn {
    margin: 0.2rem 0.3rem;
    padding: 0.1rem 0.3rem;
    cursor: pointer;
    color: #fff;
    background: #000;
    border: 1px solid #2cbcff;
    white-space: nowrap;
  }
}
